import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Card, Input, Select, Badge, Radio, icon } from 'decantr/components';

code.example:
function PayoutSettings({ settings = {}, history = [] }) {
  const { div, h2, h3, p, span, label, table, thead, tbody, tr, th, td } = tags;
  const [method, setMethod] = createSignal(settings.method || 'bank');
  const [schedule, setSchedule] = createSignal(settings.schedule || 'monthly');
  const [threshold, setThreshold] = createSignal(settings.threshold || 100);
  const [bankDetails, setBankDetails] = createSignal(settings.bankDetails || {});

  const methods = [
    { id: 'bank', name: 'Bank Transfer', desc: 'Direct deposit to your bank account', icon: 'building' },
    { id: 'paypal', name: 'PayPal', desc: 'Instant transfer to PayPal', icon: 'credit-card' },
    { id: 'stripe', name: 'Stripe', desc: 'Payout via Stripe Connect', icon: 'zap' }
  ];

  return div({ class: css('_flex _col _gap6 _maxw[800px]') },
    div({},
      h2({ class: css('_heading3 _mb2') }, 'Payout Settings'),
      p({ class: css('_fgmuted') }, 'Configure how you receive your earnings')
    ),
    Card({ class: css('studio-card _p6') },
      h3({ class: css('_heading5 _mb4') }, 'Payout Method'),
      div({ class: css('_flex _col _gap3') },
        ...methods.map(m =>
          div({
            class: css(`_flex _aic _gap4 _p4 _r3 _border _cursor[pointer] _trans ${method() === m.id ? '_borderPrimary _bgPrimary/5' : '_bordermuted _hover:bordermuted/80'}`),
            onclick: () => setMethod(m.id)
          },
            div({ class: css('_w10 _h10 _r2 _bgmuted/10 _flex _center') },
              icon(m.icon, { size: '20', class: css(method() === m.id ? '_fgPrimary' : '_fgmuted') })
            ),
            div({ class: css('_flex1') },
              span({ class: css('_fontmedium') }, m.name),
              p({ class: css('_textsm _fgmuted') }, m.desc)
            ),
            Radio({ checked: method() === m.id, name: 'payout-method' })
          )
        )
      )
    ),
    method() === 'bank' ? Card({ class: css('studio-card _p6') },
      h3({ class: css('_heading5 _mb4') }, 'Bank Account Details'),
      div({ class: css('_flex _col _gap4') },
        div({ class: css('_grid _gc1 _md:gc2 _gap4') },
          div({ class: css('_flex _col _gap2') },
            label({ class: css('_textsm _fontmedium') }, 'Account Holder Name'),
            Input({ value: bankDetails().accountName || '', placeholder: 'Full legal name' })
          ),
          div({ class: css('_flex _col _gap2') },
            label({ class: css('_textsm _fontmedium') }, 'Account Type'),
            Select({ value: bankDetails().accountType || 'checking', options: [
              { value: 'checking', label: 'Checking' },
              { value: 'savings', label: 'Savings' }
            ]})
          )
        ),
        div({ class: css('_grid _gc1 _md:gc2 _gap4') },
          div({ class: css('_flex _col _gap2') },
            label({ class: css('_textsm _fontmedium') }, 'Routing Number'),
            Input({ value: bankDetails().routing || '', placeholder: '9 digits' })
          ),
          div({ class: css('_flex _col _gap2') },
            label({ class: css('_textsm _fontmedium') }, 'Account Number'),
            Input({ value: bankDetails().account || '', placeholder: 'Account number', type: 'password' })
          )
        ),
        bankDetails().verified ? div({ class: css('_flex _aic _gap2 _p3 _r2 _bgSuccess/10') },
          icon('check-circle', { class: css('_fgSuccess') }),
          span({ class: css('_textsm _fgSuccess') }, 'Account verified')
        ) : div({ class: css('_flex _aic _gap2 _p3 _r2 _bgwarning/10') },
          icon('alert-circle', { class: css('_fgwarning') }),
          span({ class: css('_textsm') }, 'Account pending verification (1-2 business days)')
        )
      )
    ) : null,
    Card({ class: css('studio-card _p6') },
      h3({ class: css('_heading5 _mb4') }, 'Payout Schedule'),
      div({ class: css('_grid _gc1 _md:gc2 _gap4') },
        div({
          class: css(`_flex _aic _gap3 _p4 _r3 _border _cursor[pointer] ${schedule() === 'weekly' ? '_borderPrimary _bgPrimary/5' : '_bordermuted'}`),
          onclick: () => setSchedule('weekly')
        },
          Radio({ checked: schedule() === 'weekly' }),
          div({},
            span({ class: css('_fontmedium') }, 'Weekly'),
            p({ class: css('_textsm _fgmuted') }, 'Every Friday')
          )
        ),
        div({
          class: css(`_flex _aic _gap3 _p4 _r3 _border _cursor[pointer] ${schedule() === 'monthly' ? '_borderPrimary _bgPrimary/5' : '_bordermuted'}`),
          onclick: () => setSchedule('monthly')
        },
          Radio({ checked: schedule() === 'monthly' }),
          div({},
            span({ class: css('_fontmedium') }, 'Monthly'),
            p({ class: css('_textsm _fgmuted') }, '1st of each month')
          )
        )
      ),
      div({ class: css('_flex _col _gap2 _mt4') },
        label({ class: css('_textsm _fontmedium') }, 'Minimum Payout Amount'),
        div({ class: css('_flex _aic _gap2') },
          span({ class: css('_fgmuted') }, '$'),
          Input({ type: 'number', value: threshold(), onchange: (e) => setThreshold(Number(e.target.value)), class: css('_w[120px]') }),
          span({ class: css('_textsm _fgmuted') }, 'Minimum $50')
        )
      )
    ),
    Card({ class: css('studio-card _p6') },
      div({ class: css('_flex _jcsb _aic _mb4') },
        h3({ class: css('_heading5') }, 'Payout History'),
        Button({ variant: 'outline', size: 'sm' }, icon('download', { size: '14', class: css('_mr1') }), 'Download')
      ),
      history.length > 0 ? table({ class: css('_wfull') },
        thead({},
          tr({ class: css('_borderB') },
            th({ class: css('_textsm _fontmedium _fgmuted _pb3 _tl') }, 'Date'),
            th({ class: css('_textsm _fontmedium _fgmuted _pb3 _tl') }, 'Method'),
            th({ class: css('_textsm _fontmedium _fgmuted _pb3 _tr') }, 'Amount'),
            th({ class: css('_textsm _fontmedium _fgmuted _pb3 _tr') }, 'Status')
          )
        ),
        tbody({},
          ...history.map(payout =>
            tr({ class: css('_borderB _last:borderB0') },
              td({ class: css('_py3 _textsm') }, new Date(payout.date).toLocaleDateString()),
              td({ class: css('_py3 _textsm') }, payout.method),
              td({ class: css('_py3 _tr _fontmedium') }, '$', payout.amount.toFixed(2)),
              td({ class: css('_py3 _tr') },
                Badge({ variant: payout.status === 'completed' ? 'default' : 'secondary', size: 'sm' },
                  payout.status === 'completed' ? 'Completed' : 'Pending'
                )
              )
            )
          )
        )
      ) : p({ class: css('_tc _fgmuted _py8') }, 'No payouts yet')
    ),
    div({ class: css('_flex _jce _gap2') },
      Button({ variant: 'outline' }, 'Cancel'),
      Button({ variant: 'primary' }, 'Save Changes')
    )
  );
}

