function PayoutSettingsReadonly({ settings }) {
  const { div, h3, p, span } = tags;

  return Card({ class: css('studio-card _p4') },
    div({ class: css('_flex _aic _gap3 _mb4') },
      icon('credit-card', { class: css('_fgPrimary') }),
      div({},
        h3({ class: css('_fontmedium') }, 'Payout to ', settings.methodName),
        span({ class: css('_textsm _fgmuted') }, settings.accountHint)
      ),
      Badge({ variant: 'default' }, settings.schedule)
    ),
    div({ class: css('_flex _jcsb _p3 _bgmuted/5 _r2') },
      div({},
        p({ class: css('_textsm _fgmuted') }, 'Next payout'),
        p({ class: css('_fontmedium') }, settings.nextPayoutDate)
      ),
      div({ class: css('_tr') },
        p({ class: css('_textsm _fgmuted') }, 'Amount'),
        p({ class: css('_fontmedium _fgSuccess') }, '$', settings.nextPayoutAmount)
      )
    )
  );
}

